(() => {
  const API_URL = '/api/method/kiluth_portal.api.portal.get_portal_menu';
  const input = document.querySelector('#portal-menu-search');
  const categoryChips = document.querySelector('#portal-menu-chips');
  const menuList = document.querySelector('#portal-menu-list');
  const loading = document.querySelector('#loading');
  const errorMessage = document.querySelector('#error-message');
  const errorText = document.querySelector('#error-text');
  const pagination = document.querySelector('#pagination');
  const paginationList = document.querySelector('#pagination-list');
  const paginationInfo = document.querySelector('#pagination-info');

  const CACHE_NAMESPACE = 'kiluth:portal-menu-items:v1';
  const CACHE_TTL_MS = 3 * 24 * 60 * 60 * 1000;
  const ITEMS_PER_PAGE = 12;
  const SEARCH_DEBOUNCE_MS = 300;

  let currentPage = 1;
  let currentSearch = '';
  let currentCategory = '';
  let categories = [];
  let searchTimeout = null;

  const CATEGORY_LABELS = {
    sales: 'Sales & CRM', HR: 'HR', finance: 'Finance', equipment: 'Equipment',
    office: 'Office', support: 'Support', company: 'Company',
    branding: 'Branding', legal: 'Legal', tools: 'Tools'
  };
  function categoryLabel(cat) {
    return (cat && CATEGORY_LABELS[cat]) ? CATEGORY_LABELS[cat] : (cat ? cat.charAt(0).toUpperCase() + cat.slice(1) : '');
  }

  function nsKey(k) { return `${CACHE_NAMESPACE}:${k}`; }
  function makeCacheKey() {
    return btoa(encodeURIComponent(JSON.stringify({ page: currentPage, search: currentSearch || '', category: currentCategory || '' })));
  }
  function readCache(k) {
    try {
      const item = localStorage.getItem(nsKey(k));
      if (!item) return null;
      const p = JSON.parse(item);
      if (!p || typeof p.ts !== 'number') return null;
      if (Date.now() - p.ts > CACHE_TTL_MS) { localStorage.removeItem(nsKey(k)); return null; }
      return p.payload || null;
    } catch { return null; }
  }
  function writeCache(k, v) {
    try { localStorage.setItem(nsKey(k), JSON.stringify({ ts: Date.now(), payload: v })); } catch {}
  }

  function showLoading() {
    loading.style.display = 'block';
    errorMessage.style.display = 'none';
    menuList.innerHTML = '';
    if (categoryChips) categoryChips.style.display = 'none';
  }
  function hideLoading() { loading.style.display = 'none'; }
  function showError(msg) {
    hideLoading();
    errorText.textContent = msg;
    errorMessage.style.display = 'block';
    menuList.innerHTML = '';
  }

  function createCard(item) {
    const linksHtml = (item.links || []).map(link => {
      const targetAttr = link.target === '_blank' ? 'target="_blank" rel="noopener noreferrer"' : '';
      return `<a href="${link.url}" ${targetAttr} class="btn btn-outline-primary btn-sm btn-flex" aria-label="${link.label}">${link.label}</a>`;
    }).join('');
    return `
      <div class="col-12 col-md-6 col-lg-4">
        <div class="p-4 shadow-sm card h-100">
          <h5 class="mb-1">
            <i class="fa ${item.icon} me-2 ${item.iconColor}" aria-hidden="true"></i>
            ${item.title}
          </h5>
          <p class="mb-3 text-muted small">${item.description}</p>
          <div class="flex-wrap gap-2 d-flex">${linksHtml}</div>
        </div>
      </div>
    `;
  }

  function renderCategoryChips(cats) {
    if (!categoryChips || !cats || cats.length === 0) return;
    categories = [...new Set(cats)].sort();
    const allActive = !currentCategory ? 'btn-primary' : 'btn-outline-secondary';
    const chipsHtml = [
      `<button type="button" class="btn btn-chip ${allActive}" data-category="">All</button>`,
      ...categories.map(c => {
        const active = currentCategory === c ? 'btn-primary' : 'btn-outline-secondary';
        return `<button type="button" class="btn btn-chip ${active}" data-category="${c}">${categoryLabel(c)}</button>`;
      })
    ].join('');
    categoryChips.innerHTML = chipsHtml;
    categoryChips.style.display = 'flex';
    categoryChips.querySelectorAll('[data-category]').forEach(btn => {
      btn.addEventListener('click', () => {
        currentCategory = btn.getAttribute('data-category') || '';
        currentPage = 1;
        fetchPortalMenu();
      });
    });
  }

  function generatePageNumbers(current, total) {
    const pages = [];
    const maxVisible = 7;
    const sidePages = 2;
    if (total <= maxVisible) {
      for (let i = 1; i <= total; i++) pages.push(i);
    } else {
      pages.push(1);
      let start = Math.max(2, current - sidePages);
      let end = Math.min(total - 1, current + sidePages);
      if (current <= 3) { end = Math.min(5, total - 1); start = 2; }
      if (current >= total - 2) { start = Math.max(2, total - 4); end = total - 1; }
      if (start > 2) pages.push('ellipsis');
      for (let i = start; i <= end; i++) pages.push(i);
      if (end < total - 1) pages.push('ellipsis');
      pages.push(total);
    }
    return pages;
  }

  function updatePagination(p) {
    if (!p || !pagination || !paginationList || !paginationInfo) return;
    const { currentPage: cp, totalPages, totalItems, itemsPerPage } = p;
    const startItem = ((cp - 1) * itemsPerPage) + 1;
    const endItem = Math.min(cp * itemsPerPage, totalItems);
    paginationInfo.textContent = `Showing ${startItem}-${endItem} of ${totalItems} items`;

    const pages = generatePageNumbers(cp, totalPages);
    paginationList.innerHTML = pages.map(page => {
      if (page === 'ellipsis') return '<li class="page-item disabled"><span class="page-link">...</span></li>';
      const isActive = page === cp;
      if (isActive) return `<li class="page-item active"><span class="page-link">${page}</span></li>`;
      return `<li class="page-item"><a class="page-link" href="#" data-page="${page}">${page}</a></li>`;
    }).join('');

    paginationList.querySelectorAll('a[data-page]').forEach(link => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        const page = parseInt(link.getAttribute('data-page'), 10);
        if (page >= 1 && page <= totalPages && page !== currentPage) {
          currentPage = page;
          fetchPortalMenu();
        }
      });
    });

    pagination.style.display = totalPages > 1 ? 'block' : 'none';
  }

  function renderMenu(data, paginationData, cats) {
    hideLoading();
    errorMessage.style.display = 'none';

    if (cats && cats.length > 0 && categories.length === 0) renderCategoryChips(cats);
    else if (categories.length > 0) renderCategoryChips(categories);

    if (!data || data.length === 0) {
      menuList.innerHTML = '<div class="col-12"><p class="text-center text-muted">No items found.</p></div>';
      pagination.style.display = 'none';
      return;
    }

    menuList.innerHTML = data.map(createCard).join('');
    if (paginationData) updatePagination(paginationData);
  }

  async function fetchPortalMenu() {
    const cacheKey = makeCacheKey();
    const cached = readCache(cacheKey);
    if (cached && cached.success) {
      renderMenu(cached.data || [], cached.pagination, cached.categories);
      return;
    }

    showLoading();
    try {
      const params = new URLSearchParams({
        page: String(currentPage),
        limit: String(ITEMS_PER_PAGE),
        sort: 'title'
      });
      if (currentSearch) params.append('search', currentSearch);
      if (currentCategory) params.append('category', currentCategory);

      const response = await fetch(`${API_URL}?${params}`);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const raw = await response.json();
      const result = raw.message || raw;
      if (!result.success) throw new Error(result.message || 'Failed to fetch');

      writeCache(cacheKey, result);
      renderMenu(result.data || [], result.pagination, result.categories);
    } catch (err) {
      console.error('Error fetching portal menu:', err);
      showError(`Failed to load menu: ${err.message}`);
    }
  }

  function init() {
    if (input) {
      input.addEventListener('input', () => {
        clearTimeout(searchTimeout);
        searchTimeout = setTimeout(() => {
          currentSearch = input.value;
          currentPage = 1;
          fetchPortalMenu();
        }, SEARCH_DEBOUNCE_MS);
      });
    }
    fetchPortalMenu();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();

(() => {
  // TODO: migrate to https://api.kiluth.com/v1 once kiluth-api (v1) is retired
  const API_BASE_URL = 'https://v2.api.kiluth.com/v1';
  // const API_BASE_URL = 'https://elective-shiftier-myrtice.ngrok-free.dev/v1';
  const API_KEY = document.getElementById('api-config')?.dataset.key || '';

  const dropZone = document.getElementById('drop-zone');
  const fileInput = document.getElementById('file-input');
  const fileNameEl = document.getElementById('file-name');
  const pasteArea = document.getElementById('paste-area');
  const formatSelect = document.getElementById('format-select');
  const languageSelect = document.getElementById('language-select');
  const labelInput = document.getElementById('label-input');
  const btnDownload = document.getElementById('btn-download');
  const errorMsg = document.getElementById('error-msg');
  const previewLoading = document.getElementById('preview-loading');
  const previewPlaceholder = document.getElementById('preview-placeholder');
  const previewFrame = document.getElementById('preview-frame');

  let currentMarkdown = '';
  let previewDebounce = null;

  function showError(msg) {
    errorMsg.textContent = msg;
    errorMsg.classList.add('visible');
  }
  function hideError() {
    errorMsg.classList.remove('visible');
  }

  function getHeaders() {
    const h = { 'Content-Type': 'application/json' };
    if (API_KEY) h['Authorization'] = `Bearer ${API_KEY}`;
    return h;
  }

  function setMarkdown(md, fileName) {
    currentMarkdown = md;
    btnDownload.disabled = !md.trim();
    hideError();

    if (fileName) {
      fileNameEl.textContent = fileName;
      fileNameEl.style.display = 'block';
      pasteArea.value = '';
    }

    if (md.trim()) {
      clearTimeout(previewDebounce);
      previewDebounce = setTimeout(() => fetchPreview(md), 500);
    } else {
      previewFrame.style.display = 'none';
      previewPlaceholder.style.display = 'flex';
    }
  }

  // --- File upload ---
  dropZone.addEventListener('click', () => fileInput.click());
  dropZone.addEventListener('dragover', (e) => { e.preventDefault(); dropZone.classList.add('drag-over'); });
  dropZone.addEventListener('dragleave', () => dropZone.classList.remove('drag-over'));
  dropZone.addEventListener('drop', (e) => {
    e.preventDefault();
    dropZone.classList.remove('drag-over');
    const file = e.dataTransfer.files[0];
    if (file) readFile(file);
  });
  fileInput.addEventListener('change', () => {
    if (fileInput.files[0]) readFile(fileInput.files[0]);
  });

  function readFile(file) {
    if (!file.name.match(/\.(md|markdown|txt)$/i)) {
      showError('Please upload a .md file');
      return;
    }
    const reader = new FileReader();
    reader.onload = () => setMarkdown(reader.result, file.name);
    reader.onerror = () => showError('Failed to read file');
    reader.readAsText(file);
  }

  // --- Paste ---
  let pasteTimeout = null;
  pasteArea.addEventListener('input', () => {
    clearTimeout(pasteTimeout);
    pasteTimeout = setTimeout(() => {
      fileNameEl.style.display = 'none';
      fileInput.value = '';
      setMarkdown(pasteArea.value, null);
    }, 500);
  });

  // --- Preview ---
  async function fetchPreview(md) {
    previewLoading.classList.add('active');
    previewPlaceholder.style.display = 'none';
    try {
      const res = await fetch(`${API_BASE_URL}/documents/export/preview`, {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({ markdown: md, label: labelInput.value || '', language: languageSelect.value }),
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || `HTTP ${res.status}`);
      }
      const data = await res.json();
      previewFrame.srcdoc = data.html;
      previewFrame.style.display = 'block';
    } catch (err) {
      showError(`Preview failed: ${err.message}`);
      previewFrame.style.display = 'none';
      previewPlaceholder.style.display = 'flex';
    } finally {
      previewLoading.classList.remove('active');
    }
  }

  // --- Re-preview on label or language change ---
  [labelInput, languageSelect].forEach(el => {
    el.addEventListener('change', () => {
      if (currentMarkdown.trim()) {
        clearTimeout(previewDebounce);
        previewDebounce = setTimeout(() => fetchPreview(currentMarkdown), 300);
      }
    });
  });

  // --- Download ---
  btnDownload.addEventListener('click', async () => {
    if (!currentMarkdown.trim()) return;
    hideError();

    if (formatSelect.value === 'pdf') {
      const html = previewFrame.srcdoc;
      if (!html) {
        showError('Please wait for the preview to load first.');
        return;
      }
      // iOS/mobile: contentWindow.print() doesn't work — open in new tab instead
      const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
      if (isMobile) {
        const blob = new Blob([html], { type: 'text/html' });
        const url = URL.createObjectURL(blob);
        window.open(url, '_blank');
      } else {
        try {
          previewFrame.contentWindow.print();
        } catch (err) {
          // Fallback: open in new tab
          const blob = new Blob([html], { type: 'text/html' });
          const url = URL.createObjectURL(blob);
          window.open(url, '_blank');
        }
      }
      return;
    }

    const originalText = btnDownload.textContent;
    btnDownload.innerHTML = '<span class="spinner"></span>Generating...';
    btnDownload.disabled = true;

    try {
      const res = await fetch(`${API_BASE_URL}/documents/export/download`, {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          markdown: currentMarkdown,
          format: 'html',
          label: labelInput.value || '',
          language: languageSelect.value,
        }),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || `HTTP ${res.status}`);
      }

      const disposition = res.headers.get('content-disposition') || '';
      const match = disposition.match(/filename="?([^"]+)"?/);
      const filename = match ? match[1] : 'document.html';

      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    } catch (err) {
      showError(`Download failed: ${err.message}`);
    } finally {
      btnDownload.textContent = originalText;
      btnDownload.disabled = !currentMarkdown.trim();
    }
  });
})();
